export function getThirdPlaceMatrixKey(thirdGroups) {
  if (!Array.isArray(thirdGroups) || thirdGroups.length !== 8) return null;
  const normalized = thirdGroups.map((groupId) => String(groupId).toUpperCase()).sort();
  if (new Set(normalized).size !== 8) return null;
  return normalized.join(",");
}

export function allocateThirdSlotsFor(thirdGroups) {
  const key = getThirdPlaceMatrixKey(thirdGroups);
  if (!key) return null;
  const row = THIRD_PLACE_MATRIX[key];
  return row ? { ...row.allocation } : null;
}

export function getThirdPlaceMatrixOption(thirdGroups) {
  const key = getThirdPlaceMatrixKey(thirdGroups);
  return key ? THIRD_PLACE_MATRIX[key]?.option || null : null;
}
